void Main_InvokeShell() {
	printf("################################# EXAMPLES #################################\n");
	printf("# Command : WHOAMI /PRIV                                                   #\n");
	printf("################################### NOTE ###################################\n");
	printf("# If Command Prompt is disabled by the group policy, enter a command.      #\n");
	printf("############################################################################\n");
	printf("\n");
	std::string command = Input("Enter command (optional)");
	printf("\n");
	ShellExec(command);
}

