	printf("#--------------------------------------------------------------------------#\n");
	printf("# Hive   : HKEY_CURRENT_USER | HKEY_LOCAL_MACHINE                          #\n");
	printf("# Subkey : Software\\Policies\\Microsoft\\Windows\\Installer                   #\n");
	printf("# Name   : AlwaysInstallElevated                                           #\n");
